import{_ as a,c as r,o as t,aj as i}from"./chunks/framework.guNMSiFm.js";const p=JSON.parse('{"title":"Security and Access","description":"","frontmatter":{},"headers":[],"relativePath":"guide/best-practices/security-and-access.md","filePath":"guide/best-practices/security-and-access.md","lastUpdated":1777621302000}'),o={name:"guide/best-practices/security-and-access.md"};function s(n,e,c,d,l,u){return t(),r("div",null,[...e[0]||(e[0]=[i('<h1 id="security-and-access" tabindex="-1">Security and Access <a class="header-anchor" href="#security-and-access" aria-label="Permalink to &quot;Security and Access&quot;">​</a></h1><p>Security practice in Iroha should be based on narrow authority, controlled key custody, explicit network exposure, and auditable changes.</p><h2 id="key-custody" tabindex="-1">Key Custody <a class="header-anchor" href="#key-custody" aria-label="Permalink to &quot;Key Custody&quot;">​</a></h2><ul><li>Generate production keys with production-grade entropy and store private keys outside repositories, issue trackers, prompts, chat logs, and CI output.</li><li>Use separate key material for clients, peers, genesis signing, validators, fee sponsors, and technical accounts.</li><li>Rotate keys according to a written process and rehearse recovery before a live incident.</li><li>Use hardware-backed or operating-system-backed storage for high-value signing keys when the deployment risk justifies it.</li></ul><p>See <a href="/iroha-2-docs/guide/security/generating-cryptographic-keys.html">Generating Cryptographic Keys</a> and <a href="/iroha-2-docs/guide/security/storing-cryptographic-keys.html">Storing Cryptographic Keys</a>.</p><h2 id="permissions" tabindex="-1">Permissions <a class="header-anchor" href="#permissions" aria-label="Permalink to &quot;Permissions&quot;">​</a></h2><ul><li>Grant the smallest permission token or role that supports the workflow.</li><li>Prefer dedicated technical accounts for services, triggers, agents, and automation. Avoid running long-lived automation through a personal operator account.</li><li>Review permissions for peer management, metadata mutation, minting, burning, trigger registration, executor changes, and SORA/Nexus governance before production launch.</li><li>Revoke temporary permissions after the maintenance window or migration that required them.</li></ul><p>See <a href="/iroha-2-docs/blockchain/permissions.html">Permissions</a> and <a href="/iroha-2-docs/reference/permissions.html">Permission Tokens</a>.</p><h2 id="network-exposure" tabindex="-1">Network Exposure <a class="header-anchor" href="#network-exposure" aria-label="Permalink to &quot;Network Exposure&quot;">​</a></h2><ul><li>Restrict peer-to-peer, Torii, telemetry, and operator routes according to the environment. Public read access does not imply public write or operator access.</li><li>Use VPNs, firewalls, reverse proxies, TLS termination, and rate limits where appropriate for the deployment.</li><li>Keep basic-auth credentials, proxy tokens, and forwarded headers out of committed config.</li><li>Test that unauthorized clients cannot reach restricted routes.</li></ul><p>See <a href="/iroha-2-docs/guide/security/vpn.html">Virtual Private Networks</a> and <a href="/iroha-2-docs/reference/torii-endpoints.html">Torii Endpoints</a>.</p><h2 id="fraud-and-abuse-monitoring" tabindex="-1">Fraud and Abuse Monitoring <a class="header-anchor" href="#fraud-and-abuse-monitoring" aria-label="Permalink to &quot;Fraud and Abuse Monitoring&quot;">​</a></h2><ul><li>Monitor ledger events and operational signals for unexpected asset movement, permission grants, trigger changes, peer changes, and repeated rejected transactions.</li><li>Preserve evidence with transaction hashes, block heights, event records, logs, and status snapshots.</li><li>Route alerts to the security, operations, and business owners responsible for the affected assets or workflows.</li></ul><p>See <a href="/iroha-2-docs/guide/security/fraud-monitoring.html">Fraud Monitoring</a>.</p><h2 id="agent-and-automation-guardrails" tabindex="-1">Agent and Automation Guardrails <a class="header-anchor" href="#agent-and-automation-guardrails" aria-label="Permalink to &quot;Agent and Automation Guardrails&quot;">​</a></h2><ul><li>Start automation with read-only permissions and add write authority only after the workflow is reviewed.</li><li>Require explicit human approval for live-network mutations unless the automation is a deliberately deployed production service.</li><li>Do not expose private keys to agent prompts. Use local code that loads secrets from environment variables, keychains, hardware signers, or ignored config files.</li><li>Log automation decisions in a way that supports audits without leaking secret material.</li></ul>',16)])])}const m=a(o,[["render",s]]);export{p as __pageData,m as default};
